import { z } from 'zod';

export const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']),
  PORT: z.string().transform(Number).default('3000'),
  JWT_SECRET: z.string(),
  MONGODB_URI: z.string(),
  TELEGRAM_BOT_TOKEN: z.string(),
  RATE_LIMIT_WINDOW: z.string().transform(Number).default('15'),
  RATE_LIMIT_MAX: z.string().transform(Number).default('100')
});

export const env = envSchema.parse(process.env);

import { z } from 'zod';

export const createTaskSchema = z.object({
  groupId: z.string(),
  title: z.string().min(1),
  description: z.string().min(1),
  assignees: z.array(z.string()),
  recurrence: z.object({
    type: z.enum(['daily', 'weekly', 'custom']),
    daysOfWeek: z.array(z.number()).optional(),
    time: z.string().regex(/^\d{2}:\d{2}$/), // Must match 24h time format
  }),
  status: z.enum(['active', 'paused']),
});

import { ObjectId } from 'mongodb';

export interface GroupDTO {
  id: ObjectId;
  name: string;
  description: string;
  adminId: ObjectId;
  members: ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

import { GroupDTO } from '../dtos/group-dto';
import { MongoClient, ObjectId } from 'mongodb';

const client = new MongoClient(process.env.MONGODB_URI!);
const db = client.db('daily_reminder_system');
const groupsCollection = db.collection<GroupDTO>('groups');

export class GroupRepository {
  async insert(group: GroupDTO): Promise<GroupDTO> {
    const result = await groupsCollection.insertOne(group);
    return { ...group, id: result.insertedId };
  }

  async findById(id: string): Promise<GroupDTO | null> {
    return await groupsCollection.findOne({ _id: new ObjectId(id) });
  }

  // Additional methods...
}

import pino from 'pino';

export const logger = pino({
  level: process.env.NODE_ENV === 'production' ? 'info' : 'debug',
  transport: {
    target: 'pino-pretty',
    options: {
      translateTime: 'SYS:standard',
      ignore: 'pid,hostname',
    },
  },
  base: {
    pid: false,
  },
  timestamp: () => `,"timestamp":"${new Date().toISOString()}`,
});

import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';
import { sanitize } from 'express-mongo-sanitize';

export const securityMiddlewares = [
  helmet(),
  cors(),
  rateLimit({
    windowMs: parseInt(process.env.RATE_LIMIT_WINDOW || '15') * 60 * 1000, // 15 minutes
    max: parseInt(process.env.RATE_LIMIT_MAX || '100'),
    message: 'Too many requests, please try again later.',
  }),
  sanitize()
];
